import './index.css';

import {
  useState
} from 'react';

import TeacherHeader
from '../../components/common/TeacherHeader';

import {
  createStudent
} from '../../services/studentService';

function AddStudentPage() {

  const [formData, setFormData] =
    useState({

      name: '',
      email: '',
      password: '',
      role: 'student'

    });

  const [loading, setLoading] =
    useState(false);

  // HANDLE INPUT

  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  // SUBMIT FORM

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    setLoading(true);

    try {

      await createStudent(formData);

      alert(
        'Student Added Successfully'
      );

      // RESET FORM

      setFormData({

        name: '',
        email: '',
        password: '',
        role: 'student'

      });

    } catch (error) {

      console.log(error);

      alert(

        error.response?.data?.message ||

        'Failed To Add Student'

      );

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-page">

      {/* HEADER */}

      <TeacherHeader />


      {/* CONTENT */}

      <div className="student-content">

        {/* TOP */}

        <div className="student-top">

          <h1>
            Add Student
          </h1>

          <p>
            Create new student account
          </p>

        </div>


        {/* FORM */}

        <form
          className="student-form"
          onSubmit={handleSubmit}
        >

          {/* NAME */}

          <div className="input-group">

            <label>
              Student Name
            </label>

            <input
              type="text"
              name="name"
              placeholder="Enter Student Name"
              value={formData.name}
              onChange={handleChange}
              required
            />

          </div>


          {/* EMAIL */}

          <div className="input-group">

            <label>
              Student Email
            </label>

            <input
              type="email"
              name="email"
              placeholder="Enter Student Email"
              value={formData.email}
              onChange={handleChange}
              required
            />

          </div>


          {/* PASSWORD */}

          <div className="input-group">

            <label>
              Password
            </label>

            <input
              type="password"
              name="password"
              placeholder="Enter Password"
              value={formData.password}
              onChange={handleChange}
              required
            />

          </div>


          {/* BUTTON */}

          <button
            type="submit"
            disabled={loading}
          >

            {

              loading
              ? 'Adding Student...'
              : 'Add Student'

            }

          </button>

        </form>

      </div>

    </div>

  );

}

export default AddStudentPage;
